import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.klaviyo.com/en/reference/api_overview";
const PLACEHOLDER_VALUE = "pk_CoffeeSafeLocalCoffeeSafeLocalCoff";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Klaviyo API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:klaviyo",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const klaviyoFirewall = {",
    '  name: "klaviyo",',
    '  description: "Klaviyo",',
    "  placeholders: {",
    `    KLAVIYO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://a.klaviyo.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Klaviyo-API-Key ${{ secrets.KLAVIYO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Klaviyo firewall config...");
  const ts = generateTypeScript();
  writeOutput("klaviyo", ts, import.meta.dirname);
}
